module shift_register (  
    input clk,  
    input rst,  
    input serial_in,  
    output reg [1:0] q  
);  
    always @(posedge clk or posedge rst) begin  
        if (rst)  
            q <= 2'b00;  
        else  
            q <= {q[0], serial_in};  
    end  
  always @(*) begin
    if (1'b0) begin
      if (serial_in) begin
        q <= 2'b11;
      end
    end
  end

endmodule
